const rows = $input.all();
const pending = rows.filter(r => r.json.status === 'pending');

if (!pending || pending.length === 0) {
  throw new Error('No pending topics. Add more rows or reset status.');
}

// Filter by primary niche (ecommerce or saas)
const nicheFiltered = pending.filter(r => 
  r.json.industry?.toLowerCase().includes('ecommerce') ||
  r.json.industry?.toLowerCase().includes('saas') ||
  r.json.industry?.toLowerCase().includes('medical') ||
  r.json.industry?.toLowerCase().includes('sales') ||
  r.json.industry?.toLowerCase().includes('real estate')
);

const pool = nicheFiltered.length > 0 ? nicheFiltered : pending;
const pick = pool[Math.floor(Math.random() * Math.min(pool.length, 5))];

return [{
  json: {
    workflow_name: pick.json.workflow_name,
    what_it_does: pick.json.what_it_does,
    industry: pick.json.industry,
    tools_used: pick.json.tools_used,
    result_or_stat: pick.json.result_or_stat,
    hook_angle: pick.json.hook_angle
  }
}];

const raw = $input.first().json.output;
let clean = raw.replace(/```json|```/g, '').trim();
clean = clean.replace(/[\u0000-\u001F\u007F-\u009F]/g, ' ');

let parsed;
try {
  parsed = JSON.parse(clean);
} catch (e) {
  const promptMatch = clean.match(/"image_prompt":\s*"(.*?)"/s);
  const captionMatch = clean.match(/"caption_draft":\s*"(.*?)"/s);
  if (promptMatch && captionMatch) {
    parsed = { image_prompt: promptMatch[1], caption_draft: captionMatch[1] };
  } else {
    throw new Error('Parse failed: ' + clean.substring(0, 300));
  }
}

if (!parsed.image_prompt || !parsed.caption_draft) {
  throw new Error('Incomplete JSON');
}

return [{ json: { image_prompt: parsed.image_prompt, caption_draft: parsed.caption_draft } }];

const resp = $input.first().json;
const uploadUrl = resp?.value?.uploadMechanism?.['com.linkedin.digitalmedia.uploading.MediaUploadHttpRequest']?.uploadUrl;
const assetUrn = resp?.value?.asset;

if (!uploadUrl) throw new Error('No uploadUrl. Check OAuth scopes.');
if (!assetUrn) throw new Error('No asset URN.');

return [{ json: { uploadUrl, assetUrn } }];

const caption = $('SEO Enrichment').first().json.output;
const assetUrn = $('Extract Upload URL').first().json.assetUrn;
const authorUrn = $('Workflow Configuration').first().json.linkedInPersonUrn;

const cleanCaption = caption
  .replace(/[\u0000-\u001F\u007F-\u009F]/g, ' ')
  .trim();

const body = {
  author: authorUrn,
  lifecycleState: "PUBLISHED",
  specificContent: {
    "com.linkedin.ugc.ShareContent": {
      shareCommentary: { text: cleanCaption },
      shareMediaCategory: "IMAGE",
      media: [{
        status: "READY",
        description: { text: "AI generated" },
        media: assetUrn,
        title: { text: "Post" }
      }]
    }
  },
  visibility: {
    "com.linkedin.ugc.MemberNetworkVisibility": "PUBLIC"
  }
};

return [{ json: { postBody: JSON.stringify(body) } }];

const resp = $input.first().json;
const postId = resp?.id;

if (!postId) {
  throw new Error('Post failed: ' + JSON.stringify(resp).substring(0, 300));
}

return [{
  json: {
    success: true,
    postId,
    postedAt: new Date().toISOString(),
    message: 'Posted successfully'
  }
}];
